function login(openBrowser, checkMode) {
    var cookie_ = String(cookie.getKey("fanqienovel.com", "sessionid"))
    if (cookie_ && cookie_ != "" && !checkMode) {
        if (!source.variableComment) {
            java.toast("请不要重复登录，请先退出登录！")
        }
        return false
    }
    if (openBrowser) {
        try { java.startBrowserAwait("https://fanqienovel.com/", "登录")
        } catch (e) {
            java.toast(e)
        }
    }
    try {
        cookie.removeCookie("snssdk.com")
    } catch (e) {}
    var cookie_ = "sessionid=" + (String(cookie.getKey("fanqienovel.com", "sessionid")))
    let user
    try {
      user = JSON.parse(java.ajax("https://fanqienovel.com/api/user/info/v2," + JSON.stringify({
        method: "GET",
        headers: {
          "Cookie": cookie_
        }
      }))).data.name
     } catch (e) {java.log(e)}
    if (!cookie_ || cookie_ == "sessionid=" || !user) {
        java.toast("登录失败")
        return false
    }
    java.toast("欢迎 " + user + "\n登录成功！")
    return true
}

function logout() {
 cookie.removeCookie("fanqienovel.com");
    cookie.removeCookie("snssdk.com");
    java.toast("退出登录成功");
}
